export class CalendarEventDto implements ICalendarEventDto {
    id: string | undefined;
    title: string | undefined;
    type: CalendarEventType;
    startTime: moment.Moment;
    endTime: moment.Moment;
    recurrence: CalendarEventRecurrence;
    projectId: string | undefined;
    creatorUserId: number;
    creatorUser: UserDto;
    tutorId: number;
    isBusy: boolean;
    projectOfferId: string | undefined;
    projectOffer: ProjectOfferDto;
    project: ProjectDto;
    rescheduleComments: RescheduleCommentDto[] | undefined;
    userCalendarEvents: UserCalendarEventDto[] | undefined;

    constructor(data?: ICalendarEventDto) {
        if (data) {
            for (var property in data) {
                if (data.hasOwnProperty(property))
                    (<any>this)[property] = (<any>data)[property];
            }
        }
    }

    init(_data?: any) {
        if (_data) {
            this.id = _data["id"];
            this.title = _data["title"];
            this.type = _data["type"];
            this.startTime = _data["startTime"] ? moment(_data["startTime"].toString()) : <any>undefined;
            this.endTime = _data["endTime"] ? moment(_data["endTime"].toString()) : <any>undefined;
            this.recurrence = _data["recurrence"];
            this.projectId = _data["projectId"];
            this.creatorUserId = _data["creatorUserId"];
            this.creatorUser = _data["creatorUser"] ? UserDto.fromJS(_data["creatorUser"]) : <any>undefined;
            this.tutorId = _data["tutorId"];
            this.isBusy = _data["isBusy"];
            this.projectOfferId = _data["projectOfferId"];
            this.projectOffer = _data["projectOffer"] ? ProjectOfferDto.fromJS(_data["projectOffer"]) : <any>undefined;
            this.project = _data["project"] ? ProjectDto.fromJS(_data["project"]) : <any>undefined;
            if (Array.isArray(_data["rescheduleComments"])) {
                this.rescheduleComments = [] as any;
                for (let item of _data["rescheduleComments"])
                    this.rescheduleComments.push(RescheduleCommentDto.fromJS(item));
            }
            if (Array.isArray(_data["userCalendarEvents"])) {
                this.userCalendarEvents = [] as any;
                for (let item of _data["userCalendarEvents"])
                    this.userCalendarEvents.push(UserCalendarEventDto.fromJS(item));
            }
        }
    }

    static fromJS(data: any): CalendarEventDto {
        data = typeof data === 'object' ? data : {};
        let result = new CalendarEventDto();
        result.init(data);
        return result;
    }

    toJSON(data?: any) {
        data = typeof data === 'object' ? data : {};
        data["id"] = this.id;
        data["title"] = this.title;
        data["type"] = this.type;
        data["startTime"] = this.startTime ? this.startTime.toISOString() : <any>undefined;
        data["endTime"] = this.endTime ? this.endTime.toISOString() : <any>undefined;
        data["recurrence"] = this.recurrence;
        data["projectId"] = this.projectId;
        data["creatorUserId"] = this.creatorUserId;
        data["creatorUser"] = this.creatorUser ? this.creatorUser.toJSON() : <any>undefined;
        data["tutorId"] = this.tutorId;
        data["isBusy"] = this.isBusy;
        data["projectOfferId"] = this.projectOfferId;
        data["projectOffer"] = this.projectOffer ? this.projectOffer.toJSON() : <any>undefined;
        data["project"] = this.project ? this.project.toJSON() : <any>undefined;
        if (Array.isArray(this.rescheduleComments)) {
            data["rescheduleComments"] = [];
            for (let item of this.rescheduleComments)
                data["rescheduleComments"].push(item.toJSON());
        }
        if (Array.isArray(this.userCalendarEvents)) {
            data["userCalendarEvents"] = [];
            for (let item of this.userCalendarEvents)
                data["userCalendarEvents"].push(item.toJSON());
        }
        return data; 
    }

    clone(): CalendarEventDto {
        const json = this.toJSON();
        let result = new CalendarEventDto();
        result.init(json);
        return result;
    }
}

