/** 0 = OneTime 1 = Daily 2 = Weekly 3 = Monthly 4 = Yearly */
export enum CalendarEventRecurrence {
    OneTime = 0,
    Daily = 1,
    Weekly = 2,
    Monthly = 3,
    Yearly = 4,
}

/** 0 = Blocker 1 = ConfirmedBooking 2 = BookingRequest 3 = RescheduledBooking 4 = Cancelled 5 = Personal */
export enum CalendarEventType {
    Blocker = 0,
    ConfirmedBooking = 1,
    BookingRequest = 2,
    RescheduledBooking = 3,
    Cancelled = 4,
    Personal = 5,
}

/** 1 = Standard 2 = VarArgs 3 = Any 32 = HasThis 64 = ExplicitThis */
export enum CallingConventions {
    Standard = 1,
    VarArgs = 2,
    Any = 3,
    HasThis = 32,
    ExplicitThis = 64,
}

